// This translation unit is the *only* place baton-rs `#include`s the
// iRODS client headers. All Rust callers see only the opaque types and
// POD structs declared in `ffi_shim.h`. Per-version differences
// belong here behind `#ifdef` blocks.
//
// `shim_rods_conn_t` is a forward-declared opaque alias for iRODS's
// `rcComm_t` — we cast at the function boundaries. There's no separate
// allocation; the lifetime of a `shim_rods_conn_t *` is exactly the
// lifetime of the underlying `rcComm_t *` returned by `rcConnect`.

#include "ffi_shim.h"

